struct node {
	int l, r, g;
	// gcd([l, i]) == gcd([r, i]) == g
	// 最大左边界 l，最大右边界 r
};
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	int ans = 0;
	var p = vector<node>(); // r 在前，倒序排序
	fa(i, 1, n) {
		var np = vector<node>();
		np.pb({ i,i,a[i] });
		for (const var& [l, r, g] : p) {
			if (g == np.back().g)np.back().l = l;
			else np.pb({ l, r, (int)Math::gcd(g, a[i]) });
		}
		p = move(np);
		bool ok = 0;
		for (const var& [l, r, g] : p) {
			int mxlen = i - l + 1;
			int mnlen = i - r + 1;
			if (g >= mnlen and g <= mxlen) {
				ok = 1;
				break;
			}
		}
		if (ok) {
			p.clear();
			ans++;
		}
		cout << ans << ' ';
	}
	return;
}
